    [Fact]
    public void WFiltro_DtCad_WhenValidDateProvided_ShouldAddParameterAndWhereClause()
    {
        // Arrange
        var testDate = "15/06/2023";
        var filtro = new FilterFornecedores
        {
            DtCad = testDate,
            DtCad_end = string.Empty,
            LogicalOperator = TSql.And
        };
        // Act
        var result = _serviceS.WFiltroFornecedores(filtro);
        // Assert
        result.Should().NotBeNull();
        result.Value.parametros.Should().HaveCount(1);
